'use client'

import React, { useState, useEffect } from 'react'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Progress } from '@/components/ui/progress'
import { Button } from '@/components/ui/button'
import { 
  Flame, 
  Calendar, 
  Target, 
  Trophy,
  Star,
  CheckCircle2,
  Circle,
  TrendingUp,
  Award,
  Zap,
  Crown
} from 'lucide-react'
import { motion, AnimatePresence } from 'framer-motion'
import { getStudySessionStats, getStudySessionHistory } from '@/lib/study-sessions'
import { cn } from '@/lib/utils'
import { createClientComponentClient } from '@/lib/supabase'

interface StreakMilestone {
  days: number
  title: string
  description: string
  icon: React.ReactNode
  color: string
  reward?: string
}

interface DayStatus {
  date: string
  hasSession: boolean
  sessionCount: number
  accuracy?: number
}

interface StudyStreakTrackerProps {
  className?: string
  onStreakMilestone?: (milestone: StreakMilestone) => void
}

export function StudyStreakTracker({ className, onStreakMilestone }: StudyStreakTrackerProps) {
  const [streakData, setStreakData] = useState({
    currentStreak: 0,
    longestStreak: 0,
    totalSessions: 0,
    averageAccuracy: 0
  })
  const [weeklyProgress, setWeeklyProgress] = useState<DayStatus[]>([])
  const [milestones, setMilestones] = useState<StreakMilestone[]>([])
  const [isLoading, setIsLoading] = useState(true)
  const [userTimeZone, setUserTimeZone] = useState<string>('UTC')

  const streakMilestones: StreakMilestone[] = [
    {
      days: 3,
      title: 'Getting Started',
      description: 'Complete 3 consecutive days',
      icon: <Star className="w-5 h-5" />,
      color: 'text-blue-600 bg-blue-50',
      reward: 'Consistency Badge'
    },
    {
      days: 7,
      title: 'Week Warrior',
      description: 'Complete a full week',
      icon: <Target className="w-5 h-5" />,
      color: 'text-green-600 bg-green-50',
      reward: 'Weekly Champion Badge'
    },
    {
      days: 14,
      title: 'Habit Former',
      description: 'Study for 2 weeks straight',
      icon: <Zap className="w-5 h-5" />,
      color: 'text-orange-600 bg-orange-50',
      reward: 'Habit Master Badge'
    },
    {
      days: 30,
      title: 'Monthly Master',
      description: 'Complete 30 consecutive days',
      icon: <Trophy className="w-5 h-5" />,
      color: 'text-purple-600 bg-purple-50',
      reward: 'Monthly Master Badge'
    },
    {
      days: 50,
      title: 'Dedication Demon',
      description: 'Study for 50 days straight',
      icon: <Flame className="w-5 h-5" />,
      color: 'text-red-600 bg-red-50',
      reward: 'Dedication Master Badge'
    },
    {
      days: 100,
      title: 'Centurion',
      description: 'Reach the legendary 100-day streak',
      icon: <Crown className="w-5 h-5" />,
      color: 'text-yellow-600 bg-yellow-50',
      reward: 'Centurion Crown'
    }
  ]

  useEffect(() => {
    loadStreakData()
  }, [])

  const loadStreakData = async () => {
    setIsLoading(true)
    try {
      // Get overall stats
      const stats = await getStudySessionStats()
      setStreakData(stats)

      // Determine user's timezone (profile -> system -> UTC)
      const supabase = createClientComponentClient()
      let tz = Intl.DateTimeFormat().resolvedOptions().timeZone || 'UTC'
      try {
        const { data: { user } } = await supabase.auth.getUser()
        if (user) {
          const { data: profile } = await supabase
            .from('profiles')
            .select('timezone')
            .eq('id', user.id)
            .single()
          if (profile?.timezone) tz = profile.timezone
        }
      } catch (_) {
        // silent fallback to resolved/system timezone
      }
      setUserTimeZone(tz)

      // Get recent session history for weekly view
      const { data: sessions } = await getStudySessionHistory(30)
      const weeklyData = generateWeeklyProgress(sessions || [], tz)
      setWeeklyProgress(weeklyData)

      // Calculate achieved milestones
      const achievedMilestones = streakMilestones.filter(m => 
        stats.currentStreak >= m.days || stats.longestStreak >= m.days
      )
      setMilestones(achievedMilestones)

    } catch (error) {
      console.error('Failed to load streak data:', error)
    } finally {
      setIsLoading(false)
    }
  }

  const generateWeeklyProgress = (sessions: any[], timeZone: string): DayStatus[] => {
    const days: DayStatus[] = []
    const today = new Date()
    
    // Helpers for timezone-safe day math (mirror study-sessions.ts)
    const formatDateInTimeZone = (date: Date, tz: string): string => {
      const parts = new Intl.DateTimeFormat('en-CA', {
        timeZone: tz,
        year: 'numeric',
        month: '2-digit',
        day: '2-digit'
      }).formatToParts(date)
      const y = parts.find(p => p.type === 'year')?.value || '1970'
      const m = parts.find(p => p.type === 'month')?.value || '01'
      const d = parts.find(p => p.type === 'day')?.value || '01'
      return `${y}-${m}-${d}`
    }
    
    // Generate last 7 days
    for (let i = 6; i >= 0; i--) {
      const date = new Date(today)
      date.setDate(date.getDate() - i)
      const dateStr = formatDateInTimeZone(date, timeZone)
      
      const daySessions = sessions.filter(s => {
        if (!s?.ended_at || s?.status !== 'completed') return false
        const sDate = formatDateInTimeZone(new Date(s.ended_at), timeZone)
        return sDate === dateStr
      })
      
      const avgAccuracy = daySessions.length > 0 
        ? daySessions.reduce((sum, s) => sum + (s.accuracy_percentage || 0), 0) / daySessions.length
        : undefined

      days.push({
        date: dateStr,
        hasSession: daySessions.length > 0,
        sessionCount: daySessions.length,
        accuracy: avgAccuracy
      })
    }
    
    return days
  }

  const getNextMilestone = () => {
    return streakMilestones.find(m => m.days > streakData.currentStreak)
  }

  const getStreakEmoji = (streak: number) => {
    if (streak >= 100) return '👑'
    if (streak >= 50) return '🔥'
    if (streak >= 30) return '🏆'
    if (streak >= 14) return '⭐'
    if (streak >= 7) return '🎯'
    if (streak >= 3) return '💪'
    return '🌱'
  }

  const getDayName = (dateStr: string) => {
    const [y, m, d] = dateStr.split('-').map(Number)
    // Construct a UTC date at midnight for the given Y-M-D.
    // Day-of-week for a calendar date is timezone-independent.
    const date = new Date(Date.UTC(y, (m || 1) - 1, d || 1))
    return new Intl.DateTimeFormat('en', { weekday: 'short', timeZone: 'UTC' }).format(date)
  }

  const getDayNumber = (dateStr: string) => {
    // Day number is simply the D part of YYYY-MM-DD
    return parseInt(dateStr.split('-')[2] || '1', 10)
  }

  const nextMilestone = getNextMilestone()
  const progressToNext = nextMilestone 
    ? (streakData.currentStreak / nextMilestone.days) * 100 
    : 100

  if (isLoading) {
    return (
      <Card className={className}>
        <CardContent className="p-6">
          <div className="animate-pulse space-y-4">
            <div className="h-6 bg-muted rounded w-1/3" />
            <div className="h-20 bg-muted rounded" />
            <div className="grid grid-cols-7 gap-2">
              {[1,2,3,4,5,6,7].map(i => (
                <div key={i} className="h-12 bg-muted rounded" />
              ))}
            </div>
          </div>
        </CardContent>
      </Card>
    )
  }

  return (
    <Card className={className}>
      <CardHeader>
        <CardTitle className="flex items-center gap-2">
          <Flame className="w-5 h-5 text-orange-500" />
          Study Streak
        </CardTitle>
      </CardHeader>
      
      <CardContent className="space-y-6">
        {/* Current streak display */}
        <div className="text-center space-y-2">
          <motion.div
            key={streakData.currentStreak}
            initial={{ scale: 1.2 }}
            animate={{ scale: 1 }}
            transition={{ type: 'spring', duration: 0.5 }}
            className="text-6xl"
          >
            {getStreakEmoji(streakData.currentStreak)}
          </motion.div>
          
          <div className="space-y-1">
            <div className="text-3xl font-bold text-orange-600">
              {streakData.currentStreak} Days
            </div>
            <div className="text-sm text-muted-foreground">
              Current Streak • Best: {streakData.longestStreak} days
            </div>
          </div>

          {nextMilestone && (
            <div className="space-y-2">
              <div className="text-sm text-muted-foreground">
                {nextMilestone.days - streakData.currentStreak} days until 
                <span className="font-medium text-foreground"> {nextMilestone.title}</span>
              </div>
              <Progress value={progressToNext} className="h-2" />
            </div>
          )}
        </div>

        {/* Weekly progress */}
        <div className="space-y-3">
          <div className="flex items-center justify-between">
            <h4 className="font-medium">This Week</h4>
            <Badge variant="outline">
              {weeklyProgress.filter(d => d.hasSession).length}/7 days
            </Badge>
          </div>
          
          <div className="grid grid-cols-7 gap-2">
            {weeklyProgress.map((day, index) => (
              <motion.div
                key={day.date}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: index * 0.1 }}
                className="text-center"
              >
                <div className="text-xs text-muted-foreground mb-1">
                  {getDayName(day.date)}
                </div>
                <div
                  className={cn(
                    "w-8 h-8 mx-auto rounded-full flex items-center justify-center text-xs font-medium transition-all",
                    day.hasSession
                      ? "bg-green-500 text-white"
                      : "bg-muted text-muted-foreground"
                  )}
                >
                  {day.hasSession ? (
                    <CheckCircle2 className="w-4 h-4" />
                  ) : (
                    <Circle className="w-4 h-4" />
                  )}
                </div>
                <div className="text-xs mt-1">
                  {getDayNumber(day.date)}
                </div>
                {day.hasSession && day.sessionCount > 1 && (
                  <Badge variant="secondary" className="text-xs mt-1">
                    {day.sessionCount}
                  </Badge>
                )}
              </motion.div>
            ))}
          </div>
        </div>

        {/* Milestone achievements */}
        {milestones.length > 0 && (
          <div className="space-y-3">
            <h4 className="font-medium flex items-center gap-2">
              <Award className="w-4 h-4" />
              Achievements
            </h4>
            
            <div className="grid grid-cols-1 gap-2">
              {milestones.slice(-3).map((milestone, index) => (
                <motion.div
                  key={milestone.days}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: index * 0.1 }}
                  className={cn(
                    "flex items-center gap-3 p-3 rounded-lg border",
                    milestone.color
                  )}
                >
                  <div className="flex-shrink-0">
                    {milestone.icon}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="font-medium text-sm">{milestone.title}</div>
                    <div className="text-xs opacity-75">{milestone.description}</div>
                  </div>
                  <Badge variant="secondary" className="text-xs">
                    {milestone.days} days
                  </Badge>
                </motion.div>
              ))}
            </div>
          </div>
        )}

        {/* Next milestone preview */}
        {nextMilestone && (
          <div className="space-y-3">
            <h4 className="font-medium">Next Goal</h4>
            
            <div className={cn(
              "flex items-center gap-3 p-3 rounded-lg border border-dashed",
              nextMilestone.color
            )}>
              <div className="flex-shrink-0">
                {nextMilestone.icon}
              </div>
              <div className="flex-1">
                <div className="font-medium text-sm">{nextMilestone.title}</div>
                <div className="text-xs opacity-75">{nextMilestone.description}</div>
                {nextMilestone.reward && (
                  <div className="text-xs mt-1 font-medium">
                    Reward: {nextMilestone.reward}
                  </div>
                )}
              </div>
              <div className="text-right">
                <div className="font-bold text-lg">{nextMilestone.days}</div>
                <div className="text-xs opacity-75">days</div>
              </div>
            </div>
          </div>
        )}

        {/* Stats summary */}
        <div className="grid grid-cols-2 gap-4 pt-4 border-t">
          <div className="text-center">
            <div className="text-2xl font-bold text-blue-600">
              {streakData.totalSessions}
            </div>
            <div className="text-xs text-muted-foreground">Total Sessions</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-purple-600">
              {streakData.averageAccuracy}%
            </div>
            <div className="text-xs text-muted-foreground">Avg Accuracy</div>
          </div>
        </div>
      </CardContent>
    </Card>
  )
}

'use client'

import { useState, useEffect } from 'react'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Checkbox } from '@/components/ui/checkbox'
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog'
import { ScrollArea } from '@/components/ui/scroll-area'
import { FolderPlus, Check, X } from 'lucide-react'
import { getUserDesks, getWordDesks, addWordToDesk, removeWordFromDesk, Desk } from '@/lib/desks'
import { useToast } from '@/components/ui/toast'

interface WordDeskAssignmentProps {
  wordId: string
  wordText: string
  trigger?: React.ReactNode
}

export function WordDeskAssignment({ wordId, wordText, trigger }: WordDeskAssignmentProps) {
  const [isOpen, setIsOpen] = useState(false)
  const [allDesks, setAllDesks] = useState<Desk[]>([])
  const [wordDesks, setWordDesks] = useState<Desk[]>([])
  const [isLoading, setIsLoading] = useState(false)
  const [isUpdating, setIsUpdating] = useState(false)
  const { success, error } = useToast()

  useEffect(() => {
    if (isOpen) {
      loadData()
    }
  }, [isOpen, wordId])

  const loadData = async () => {
    setIsLoading(true)
    try {
      const [desksResult, wordDesksResult] = await Promise.all([
        getUserDesks(),
        getWordDesks(wordId)
      ])

      if (desksResult.error) {
        error({
          title: 'Error',
          description: 'Failed to load desks'
        })
      } else {
        setAllDesks(desksResult.data || [])
      }

      if (wordDesksResult.error) {
        error({
          title: 'Error',
          description: 'Failed to load word desks'
        })
      } else {
        setWordDesks(wordDesksResult.data || [])
      }
    } catch (error) {
      console.error('Failed to load data:', error)
    } finally {
      setIsLoading(false)
    }
  }

  const handleDeskToggle = async (desk: Desk, isCurrentlyAssigned: boolean) => {
    setIsUpdating(true)
    try {
      let apiError
      if (isCurrentlyAssigned) {
        const result = await removeWordFromDesk(wordId, desk.id)
        apiError = result.error
      } else {
        const result = await addWordToDesk(wordId, desk.id)
        apiError = result.error
      }

      if (apiError) {
        error({
          title: 'Error',
          description: apiError.message || 'Failed to update desk assignment'
        })
      } else {
        // Update local state
        if (isCurrentlyAssigned) {
          setWordDesks(prev => prev.filter(d => d.id !== desk.id))
        } else {
          setWordDesks(prev => [...prev, desk])
        }
        
        success({
          title: 'Success',
          description: `Word ${isCurrentlyAssigned ? 'removed from' : 'added to'} ${desk.name}`
        })
      }
    } catch (error) {
      console.error('Failed to toggle desk assignment:', error)
    } finally {
      setIsUpdating(false)
    }
  }

  const getIconComponent = (iconName: string) => {
    // Simple mapping for common icons - you can expand this
    const iconMap: Record<string, React.ReactNode> = {
      'book-open': '📖',
      'folder': '📁',
      'star': '⭐',
      'users': '👥',
      'globe': '🌍',
      'heart': '❤️',
      'zap': '⚡',
      'target': '🎯',
      'brain': '🧠'
    }
    return iconMap[iconName] || '📖'
  }

  return (
    <Dialog open={isOpen} onOpenChange={setIsOpen}>
      <DialogTrigger asChild>
        {trigger || (
          <Button variant="outline" size="sm">
            <FolderPlus className="w-4 h-4 mr-2" />
            Manage Desks
          </Button>
        )}
      </DialogTrigger>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle>Manage Desks for &quot;{wordText}&quot;</DialogTitle>
        </DialogHeader>
        
        {isLoading ? (
          <div className="py-8">
            <div className="flex items-center justify-center">
              <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
            </div>
          </div>
        ) : (
          <ScrollArea className="max-h-96">
            <div className="space-y-2">
              {allDesks.map(desk => {
                const isAssigned = wordDesks.some(wd => wd.id === desk.id)
                
                return (
                  <div
                    key={desk.id}
                    className="flex items-center space-x-3 p-3 rounded-lg border hover:bg-muted/50 transition-colors"
                  >
                    <Checkbox
                      id={`desk-${desk.id}`}
                      checked={isAssigned}
                      onCheckedChange={() => handleDeskToggle(desk, isAssigned)}
                      disabled={isUpdating}
                    />
                    <div className="flex items-center gap-2 flex-1">
                      <span className="text-lg">{getIconComponent(desk.icon)}</span>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-2">
                          <label 
                            htmlFor={`desk-${desk.id}`}
                            className="font-medium cursor-pointer truncate"
                          >
                            {desk.name}
                          </label>
                          {desk.is_default && (
                            <Badge variant="secondary" className="text-xs">Default</Badge>
                          )}
                        </div>
                        {desk.description && (
                          <p className="text-sm text-muted-foreground truncate">
                            {desk.description}
                          </p>
                        )}
                        <p className="text-xs text-muted-foreground">
                          {desk.word_count || 0} words
                        </p>
                      </div>
                    </div>
                    {isAssigned && (
                      <Check className="w-4 h-4 text-green-600" />
                    )}
                  </div>
                )
              })}
              
              {allDesks.length === 0 && (
                <div className="text-center py-8 text-muted-foreground">
                  <FolderPlus className="w-12 h-12 mx-auto mb-4 opacity-50" />
                  <p>No desks available</p>
                  <p className="text-sm">Create a desk first to organize your words</p>
                </div>
              )}
            </div>
          </ScrollArea>
        )}
        
        <div className="flex justify-between items-center pt-4 border-t">
          <div className="text-sm text-muted-foreground">
            {wordDesks.length} desk{wordDesks.length !== 1 ? 's' : ''} selected
          </div>
          <Button variant="outline" onClick={() => setIsOpen(false)}>
            Done
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  )
}

export default WordDeskAssignment

'use client'

import React, { useState, useEffect, useCallback, useRef } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Card, CardContent } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Button } from '@/components/ui/button'
import { 
  FlashcardState, 
  FlashcardAnswer, 
  FlashcardSentence,
  ReviewQuality,
  ReviewResult,
  Word
} from '@/types'
import { ClozeTest } from './ClozeTest'
import { FlashcardImage } from './FlashcardImage'
import { FlashcardNavigation } from './FlashcardNavigation'
import { 
  Volume2, 
  RotateCcw, 
  Check, 
  X, 
  ChevronLeft, 
  ChevronRight,
  Clock,
  Edit,
  Lightbulb
} from 'lucide-react'
import { cn } from '@/lib/utils'
import { DIFFICULTY_LEVELS } from '@/lib/words'
import WordEditModal from '@/components/words/WordEditModal'
import { aiService } from '@/lib/ai-services'

const FLIP_ANIMATION = {
  initial: { rotateY: 0 },
  animate: { rotateY: 180 },
  exit: { rotateY: 0 }
}

const CARD_VARIANTS = {
  enter: { scale: 0.95, opacity: 0, x: 50 },
  center: { scale: 1, opacity: 1, x: 0 },
  exit: { scale: 0.95, opacity: 0, x: -50 }
}

interface FlashcardComponentProps {
  word: Word
  sentences: FlashcardSentence[] | null
  imageUrl: string | null
  imageDescription?: string | null
  isGeneratingContent: boolean
  contentGenerationError?: string | null
  onRegenerateContent?: () => void
  onReview: (result: ReviewResult) => void
  onNext?: () => void
  onPrevious?: () => void
  showNavigation?: boolean
  autoFlip?: boolean
  className?: string
  onWordUpdated?: (updatedWord: Word) => void
}

export function FlashcardComponent({
  word,
  sentences,
  imageUrl,
  imageDescription,
  isGeneratingContent,
  contentGenerationError,
  onRegenerateContent,
  onReview,
  onNext,
  onPrevious,
  showNavigation = false,
  autoFlip = false,
  className,
  onWordUpdated
}: FlashcardComponentProps) {
  const [state, setState] = useState<FlashcardState>({
    isFlipped: false,
    currentSentenceIndex: 0,
    userInput: '',
    isCorrect: undefined,
    showFeedback: false,
    responseTime: 0
  })

  const [startTime] = useState(Date.now())
  const [showEditModal, setShowEditModal] = useState(false)
  const [currentWord, setCurrentWord] = useState<Word>(word)
  const [audioUrl, setAudioUrl] = useState<string | null>(null)
  const [isLoadingAudio, setIsLoadingAudio] = useState(false)
  const [audioError, setAudioError] = useState<string | null>(null)
  const audioRef = useRef<HTMLAudioElement | null>(null)
  const cardRef = useRef<HTMLDivElement>(null)

  // Reset audio state when word changes
  useEffect(() => {
    setCurrentWord(word)
    setAudioUrl(null)
    setAudioError(null)
    setIsLoadingAudio(false)
  }, [word.id])

  const handleFlip = useCallback(() => {
    setState(prev => ({
      ...prev,
      isFlipped: !prev.isFlipped,
      responseTime: Date.now() - startTime
    }))
  }, [startTime])

  // Keyboard shortcuts
  useEffect(() => {
    const handleKeyPress = (e: KeyboardEvent) => {
      if (e.target instanceof HTMLInputElement) return

      switch (e.key) {
        case ' ':
          e.preventDefault()
          // In new flow, Space shows answer (flips from front to back)
          if (!state.isFlipped) {
            handleFlip()
          }
          break
        case 'ArrowLeft':
          e.preventDefault()
          onPrevious?.()
          break
        case 'ArrowRight':
          e.preventDefault()
          if (state.isFlipped) onNext?.()
          break
        case '1':
        case '2':
        case '3':
        case '4':
        case '5':
          if (state.isFlipped) {
            handleReview(parseInt(e.key) as ReviewQuality)
          }
          break
      }
    }

    document.addEventListener('keydown', handleKeyPress)
    return () => document.removeEventListener('keydown', handleKeyPress)
  }, [state.isFlipped, onNext, onPrevious, handleFlip])

  const handleShowAnswer = useCallback((e: React.MouseEvent) => {
    e.stopPropagation()
    if (!state.isFlipped) {
      handleFlip()
    }
  }, [state.isFlipped, handleFlip])

  const handleClozeAnswer = useCallback((answer: FlashcardAnswer) => {
    setState(prev => ({
      ...prev,
      isCorrect: answer.isCorrect,
      showFeedback: true,
      responseTime: answer.responseTimeMs
    }))

    // Auto-flip immediately after answer submission (new active recall flow)
    setTimeout(() => {
      setState(prev => ({ ...prev, isFlipped: true }))
    }, 800)
  }, [])

  const handleReview = useCallback((quality: ReviewQuality) => {
    onReview({
      quality,
      response_time_ms: state.responseTime
    })
  }, [onReview, state.responseTime])

  const fetchAudio = useCallback(async () => {
    if (!currentWord.id) return

    setIsLoadingAudio(true)
    setAudioError(null)

    try {
      const { audioUrl: newAudioUrl } = await aiService.generateAudio(
        currentWord.word, 
        currentWord.id
      )
      setAudioUrl(newAudioUrl)
    } catch (error) {
      console.error('Failed to generate audio:', error)
      setAudioError('Failed to load audio')
    } finally {
      setIsLoadingAudio(false)
    }
  }, [currentWord.id, currentWord.word])

  const playAudio = useCallback(() => {
    if (audioUrl) {
      if (audioRef.current) {
        audioRef.current.play().catch(console.error)
      } else {
        // Create a new audio element if ref is not available
        const audio = new Audio(audioUrl)
        audio.play().catch(console.error)
      }
    } else if (!isLoadingAudio && !audioError) {
      // First time - fetch the audio
      fetchAudio()
    }
  }, [audioUrl, isLoadingAudio, audioError, fetchAudio])

  const resetCard = useCallback(() => {
    setState({
      isFlipped: false,
      currentSentenceIndex: 0,
      userInput: '',
      isCorrect: undefined,
      showFeedback: false,
      responseTime: 0
    })
    // Reset audio state
    setAudioUrl(null)
    setAudioError(null)
    setIsLoadingAudio(false)
  }, [])

  // Touch/swipe gestures
  const handleSwipe = useCallback((direction: 'left' | 'right') => {
    if (direction === 'left') {
      onNext?.()
    } else if (direction === 'right') {
      onPrevious?.()
    }
  }, [onNext, onPrevious])

  const handleEditWord = useCallback(() => {
    setShowEditModal(true)
  }, [])

  const handleWordUpdated = useCallback((updatedWord: Word) => {
    setCurrentWord(updatedWord)
    setShowEditModal(false)
    onWordUpdated?.(updatedWord)
  }, [onWordUpdated])

  const handleCloseEditModal = useCallback(() => {
    setShowEditModal(false)
  }, [])

  return (
    <motion.div 
      className={cn("relative w-full max-w-2xl mx-auto", className)}
      variants={CARD_VARIANTS}
      initial="enter"
      animate="center"
      exit="exit"
      transition={{ duration: 0.3, ease: "easeInOut" }}
    >
      {/* Hidden audio element for playback */}
      {audioUrl && (
        <audio
          ref={audioRef}
          src={audioUrl}
          preload="metadata"
          className="sr-only"
        />
      )}

      {/* Main flashcard */}
      <div 
        ref={cardRef}
        className="relative h-[500px] sm:h-[480px] md:h-[520px] lg:h-[580px] perspective-1000"
        role="button"
        aria-label={`Flashcard for word ${currentWord.word}. ${state.isFlipped ? 'Back side showing word and definition' : 'Front side showing practice exercises'}`}
        tabIndex={0}
      >
        <motion.div
          className="relative w-full h-full preserve-3d"
          animate={{ rotateY: state.isFlipped ? 180 : 0 }}
          transition={{ duration: 0.6, ease: "easeInOut" }}
        >
          {/* Front of card - Now shows cloze test exercises */}
          <Card 
            className="absolute inset-0 backface-hidden border-2 border-primary/20"
            role="main"
            aria-label="Flashcard exercises - fill in the blanks to practice active recall"
          >
            <CardContent className="p-4 sm:p-6 md:p-8 h-full flex flex-col">
              {/* Header */}
              <div className="flex items-center justify-between mb-4 sm:mb-6">
                <div className="flex items-center gap-2 sm:gap-3">
                  <h3 className="text-lg sm:text-xl md:text-2xl font-semibold truncate">Practice</h3>
                  <Badge 
                    variant="secondary"
                    className={DIFFICULTY_LEVELS[currentWord.difficulty as keyof typeof DIFFICULTY_LEVELS]?.color}
                  >
                    {DIFFICULTY_LEVELS[currentWord.difficulty as keyof typeof DIFFICULTY_LEVELS]?.label}
                  </Badge>
                  {currentWord.category && (
                    <Badge variant="outline">{currentWord.category}</Badge>
                  )}
                </div>
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleShowAnswer}
                  className="gap-1 sm:gap-2 text-xs sm:text-sm"
                  title="Reveal the answer without guessing"
                >
                  <Clock className="w-3 h-3 sm:w-4 sm:h-4" />
                  <span className="hidden sm:inline">Show Answer</span>
                  <span className="sm:hidden">Show</span>
                </Button>
              </div>

              {/* Cloze test sentences - with dynamic loading states */}
              <div className="flex-1 space-y-4 sm:space-y-4 md:space-y-6 overflow-y-auto">
                {isGeneratingContent ? (
                  <div className="space-y-4">
                    <div className="flex items-center justify-center py-8">
                      <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
                    </div>
                    <p className="text-center text-muted-foreground">
                      Generating fresh content for practice...
                    </p>
                  </div>
                ) : contentGenerationError ? (
                  <div className="space-y-4">
                    <div className="text-center py-8">
                      <div className="w-16 h-16 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
                        <X className="w-8 h-8 text-red-600" />
                      </div>
                      <h3 className="text-lg font-semibold text-red-800 mb-2">
                        Generation Failed
                      </h3>
                      <p className="text-red-600 mb-4">{contentGenerationError}</p>
                      {onRegenerateContent && (
                        <Button onClick={onRegenerateContent} variant="outline" size="sm">
                          Try Again
                        </Button>
                      )}
                    </div>
                  </div>
                ) : sentences && sentences.length > 0 ? (
                  <>
                    <div className="text-center mb-6">
                      <p className="text-sm text-muted-foreground mb-2">
                        Fill in the blanks with the correct word:
                      </p>
                    </div>
                    {sentences.map((sentence, index) => (
                      <ClozeTest
                        key={index}
                        sentence={sentence}
                        onAnswer={handleClozeAnswer}
                        isRevealed={state.showFeedback}
                      />
                    ))}
                  </>
                ) : (
                  <div className="text-center py-8 text-muted-foreground">
                    No sentences available
                  </div>
                )}
              </div>

              {/* Instructions */}
              <div className="mt-4 text-center">
                <p className="text-sm text-muted-foreground">
                  Think about the context, then type your answer and press Enter
                </p>
              </div>
            </CardContent>
          </Card>

          {/* Back of card - Now shows word, definition, image, and review buttons */}
          <Card 
            className="absolute inset-0 backface-hidden rotate-y-180 border-2 border-border/50 hover:border-primary/20 transition-colors"
            role="img"
            aria-label={`Answer revealed - Word: ${currentWord.word}. Definition: ${currentWord.definition}`}
          >
            <CardContent className="p-4 sm:p-6 md:p-8 h-full flex flex-col">
              {/* Header with controls */}
              <div className="flex items-center justify-between mb-4 sm:mb-6">
                <div className="flex items-center gap-2 sm:gap-3">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={(e) => {
                      e.stopPropagation()
                      playAudio()
                    }}
                    disabled={isLoadingAudio || !!audioError}
                    className="gap-2"
                    title={
                      audioError 
                        ? audioError 
                        : isLoadingAudio 
                        ? 'Generating audio...' 
                        : 'Play pronunciation'
                    }
                  >
                    {isLoadingAudio ? (
                      <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-primary"></div>
                    ) : (
                      <Volume2 className={cn("w-4 h-4", audioError && "text-red-500")} />
                    )}
                  </Button>
                </div>
                <div className="flex gap-1 sm:gap-2">
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={(e) => {
                      e.stopPropagation()
                      handleEditWord()
                    }}
                    className="gap-1 sm:gap-2 text-xs sm:text-sm"
                  >
                    <Edit className="w-3 h-3 sm:w-4 sm:h-4" />
                    <span className="hidden sm:inline">Edit</span>
                  </Button>
                  <Button
