      {/* Edit Modal */}
      {showEditModal && (
        <WordEditModal
          word={currentWord}
          onWordUpdated={handleWordUpdated}
          onClose={handleCloseEditModal}
        />
      )}
    </motion.div>
  )
}

'use client'

import { useState, useEffect } from 'react'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { formatInterval, previewIntervals } from '@/utils/sm2'
import { getNextReviewPrediction } from '@/lib/reviews'
import { Clock, TrendingUp, TrendingDown, Minus } from 'lucide-react'
import { cn } from '@/lib/utils'

interface ReviewButtonsProps {
  wordId: string
  onReview: (button: 'again' | 'hard' | 'good' | 'easy') => void
  disabled?: boolean
  showPreview?: boolean
  currentEaseFactor?: number
  currentInterval?: number
  currentRepetitions?: number
  className?: string
}

interface ButtonConfig {
  key: 'again' | 'hard' | 'good' | 'easy'
  label: string
  shortcut: string
  description: string
  color: string
  hoverColor: string
  icon?: React.ReactNode
}

const buttonConfigs: ButtonConfig[] = [
  {
    key: 'again',
    label: 'Again',
    shortcut: '1',
    description: 'Complete blackout - start over',
    color: 'bg-red-500 text-white',
    hoverColor: 'hover:bg-red-600',
    icon: <TrendingDown className="w-4 h-4" />
  },
  {
    key: 'hard',
    label: 'Hard',
    shortcut: '2', 
    description: 'Difficult recall - reduce ease',
    color: 'bg-orange-500 text-white',
    hoverColor: 'hover:bg-orange-600',
    icon: <Minus className="w-4 h-4" />
  },
  {
    key: 'good',
    label: 'Good',
    shortcut: '3',
    description: 'Recalled with effort - normal progression',
    color: 'bg-blue-500 text-white', 
    hoverColor: 'hover:bg-blue-600',
    icon: <Clock className="w-4 h-4" />
  },
  {
    key: 'easy',
    label: 'Easy',
    shortcut: '4',
    description: 'Perfect recall - increase ease',
    color: 'bg-green-500 text-white',
    hoverColor: 'hover:bg-green-600',
    icon: <TrendingUp className="w-4 h-4" />
  }
]

export function ReviewButtons({
  wordId,
  onReview,
  disabled = false,
  showPreview = true,
  currentEaseFactor = 2.5,
  currentInterval = 1,
  currentRepetitions = 0,
  className
}: ReviewButtonsProps) {
  const [intervals, setIntervals] = useState<Record<string, number>>({})
  const [hoveredButton, setHoveredButton] = useState<string | null>(null)
  const [isLoading, setIsLoading] = useState(false)

  // Load interval predictions
  useEffect(() => {
    if (showPreview && wordId) {
      loadIntervalPredictions()
    } else {
      // Use current values for preview
      const previewData = previewIntervals(currentEaseFactor, currentInterval, currentRepetitions)
      setIntervals(previewData)
    }
  }, [wordId, showPreview, currentEaseFactor, currentInterval, currentRepetitions])

  const loadIntervalPredictions = async () => {
    setIsLoading(true)
    try {
      const { intervals: predictedIntervals } = await getNextReviewPrediction(wordId)
      setIntervals(predictedIntervals)
    } catch (error) {
      console.error('Failed to load interval predictions:', error)
      // Fallback to current values
      const previewData = previewIntervals(currentEaseFactor, currentInterval, currentRepetitions)
      setIntervals(previewData)
    } finally {
      setIsLoading(false)
    }
  }

  // Keyboard shortcuts
  useEffect(() => {
    const handleKeyPress = (e: KeyboardEvent) => {
      if (disabled) return

      const key = e.key
      const buttonConfig = buttonConfigs.find(config => config.shortcut === key)

      if (buttonConfig && !e.ctrlKey && !e.metaKey && !e.altKey) {
        e.preventDefault()
        onReview(buttonConfig.key)
      }
    }

    window.addEventListener('keydown', handleKeyPress)
    return () => window.removeEventListener('keydown', handleKeyPress)
  }, [disabled, onReview])

  const handleButtonClick = (button: 'again' | 'hard' | 'good' | 'easy') => {
    if (disabled) return
    onReview(button)
  }

  return (
    <div className={cn('flex flex-col gap-4', className)}>
      {/* Interval Preview */}
      {showPreview && (
        <div className="bg-muted/50 rounded-lg p-3">
          <div className="text-sm font-medium text-muted-foreground mb-2 flex items-center gap-2">
            <Clock className="w-4 h-4" />
            Next Review Times
            {isLoading && <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin" />}
          </div>
          <div className="grid grid-cols-4 gap-2 text-xs">
            {buttonConfigs.map(config => (
              <div key={config.key} className="text-center">
                <div className="font-medium">{config.label}</div>
                <div className="text-muted-foreground">
                  {formatInterval(intervals[config.key] || 0)}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Review Buttons */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
        {buttonConfigs.map(config => (
          <div key={config.key} className="relative">
            <Button
              onClick={() => handleButtonClick(config.key)}
              onMouseEnter={() => setHoveredButton(config.key)}
              onMouseLeave={() => setHoveredButton(null)}
              disabled={disabled}
              className={cn(
                'w-full h-14 flex flex-col items-center justify-center gap-1 transition-all',
                config.color,
                config.hoverColor,
                'hover:scale-105 active:scale-95',
                disabled && 'opacity-50 cursor-not-allowed'
              )}
            >
              {config.icon}
              <span className="font-semibold">{config.label}</span>
              <Badge 
                variant="secondary" 
                className="absolute -top-2 -right-2 w-6 h-6 p-0 flex items-center justify-center bg-black/20 text-white text-xs"
              >
                {config.shortcut}
              </Badge>
            </Button>

            {/* Tooltip */}
            {hoveredButton === config.key && (
              <div className="absolute bottom-full left-1/2 transform -translate-x-1/2 mb-2 z-50">
                <div className="bg-black text-white text-xs rounded px-2 py-1 whitespace-nowrap">
                  {config.description}
                  <div className="absolute top-full left-1/2 transform -translate-x-1/2 border-4 border-transparent border-t-black" />
                </div>
              </div>
            )}
          </div>
        ))}
      </div>

      {/* Keyboard Shortcuts Hint */}
      <div className="text-xs text-muted-foreground text-center">
        Use keyboard shortcuts 1-4 for quick review
      </div>
    </div>
  )
}

export default ReviewButtons

'use client'

import React, { useState, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Progress } from '@/components/ui/progress'
import { 
  Award, 
  Target, 
  Clock, 
  TrendingUp, 
  CheckCircle2, 
  Star,
  Trophy,
  Flame,
  Brain,
  Zap,
  RotateCcw,
  ArrowRight,
  Calendar
} from 'lucide-react'
import { cn } from '@/lib/utils'
import { getStudySessionStats } from '@/lib/study-sessions'

interface SessionStats {
  cardsStudied: number
  cardsCorrect: number
  totalReviews: number
  accuracy: number
  duration: number
  averageResponseTime: number
}

interface Achievement {
  id: string
  title: string
  description: string
  icon: React.ReactNode
  unlocked: boolean
  progress?: number
  maxProgress?: number
}

interface SessionCompletionFeedbackProps {
  sessionStats: SessionStats
  sessionType: string
  onRestart: () => void
  onExit: () => void
  className?: string
}

export function SessionCompletionFeedback({
  sessionStats,
  sessionType,
  onRestart,
  onExit,
  className
}: SessionCompletionFeedbackProps) {
  const [achievements, setAchievements] = useState<Achievement[]>([])
  const [overallStats, setOverallStats] = useState({
    totalSessions: 0,
    currentStreak: 0,
    totalWordsStudied: 0,
    averageAccuracy: 0
  })
  const [showAchievements, setShowAchievements] = useState(false)

  useEffect(() => {
    loadAchievementsAndStats()
  }, [sessionStats])

  const loadAchievementsAndStats = async () => {
    const stats = await getStudySessionStats()
    setOverallStats(stats)

    const newAchievements = calculateAchievements(sessionStats, stats)
    setAchievements(newAchievements)

    // Show achievements if any were unlocked
    const hasNewAchievements = newAchievements.some(a => a.unlocked)
    if (hasNewAchievements) {
      setTimeout(() => setShowAchievements(true), 1000)
    }
  }

  const calculateAchievements = (session: SessionStats, overall: any): Achievement[] => {
    const achievements: Achievement[] = []

    // Perfect Session
    if (session.accuracy === 100 && session.cardsStudied >= 5) {
      achievements.push({
        id: 'perfect_session',
        title: 'Perfect Session!',
        description: `Got 100% accuracy with ${session.cardsStudied} cards`,
        icon: <Trophy className="w-6 h-6 text-yellow-500" />,
        unlocked: true
      })
    }

    // Speed Demon
    const avgTimePerCard = session.duration / session.cardsStudied
    if (avgTimePerCard <= 30 && session.accuracy >= 80) {
      achievements.push({
        id: 'speed_demon',
        title: 'Speed Demon',
        description: 'Completed cards in under 30 seconds each with 80%+ accuracy',
        icon: <Zap className="w-6 h-6 text-blue-500" />,
        unlocked: true
      })
    }

    // Streak Master
    if (overall.currentStreak >= 7) {
      achievements.push({
        id: 'streak_master',
        title: 'Streak Master',
        description: `${overall.currentStreak} day study streak!`,
        icon: <Flame className="w-6 h-6 text-orange-500" />,
        unlocked: true
      })
    }

    // Marathon Session
    if (session.cardsStudied >= 50) {
      achievements.push({
        id: 'marathon',
        title: 'Marathon Session',
        description: `Studied ${session.cardsStudied} cards in one session`,
        icon: <Target className="w-6 h-6 text-green-500" />,
        unlocked: true
      })
    }

    // Scholar
    if (overall.totalWordsStudied >= 1000) {
      achievements.push({
        id: 'scholar',
        title: 'Scholar',
        description: `Studied ${overall.totalWordsStudied} total words`,
        icon: <Brain className="w-6 h-6 text-purple-500" />,
        unlocked: true
      })
    }

    // Progress achievements (not unlocked, showing progress)
    achievements.push({
      id: 'daily_goal',
      title: 'Daily Goal',
      description: 'Complete 20 cards today',
      icon: <Calendar className="w-6 h-6 text-blue-400" />,
      unlocked: false,
      progress: Math.min(session.cardsStudied, 20),
      maxProgress: 20
    })

    return achievements
  }

  const getPerformanceLevel = (accuracy: number): { level: string; color: string; message: string } => {
    if (accuracy >= 95) return {
      level: 'Exceptional',
      color: 'text-yellow-600 bg-yellow-50',
      message: 'Outstanding performance! You\'ve mastered these words.'
    }
    if (accuracy >= 85) return {
      level: 'Excellent',
      color: 'text-green-600 bg-green-50',
      message: 'Great job! Your retention is very strong.'
    }
    if (accuracy >= 75) return {
      level: 'Good',
      color: 'text-blue-600 bg-blue-50',
      message: 'Solid progress! Keep up the good work.'
    }
    if (accuracy >= 65) return {
      level: 'Fair',
      color: 'text-orange-600 bg-orange-50',
      message: 'You\'re improving! Consider reviewing these words more.'
    }
    return {
      level: 'Needs Work',
      color: 'text-red-600 bg-red-50',
      message: 'These words need more practice. Don\'t give up!'
    }
  }

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60)
    const secs = seconds % 60
    return `${mins}:${secs.toString().padStart(2, '0')}`
  }

  const performance = getPerformanceLevel(sessionStats.accuracy)
  const unlockedAchievements = achievements.filter(a => a.unlocked)

  return (
    <motion.div
      className={cn("max-w-4xl mx-auto space-y-6", className)}
      initial={{ opacity: 0, scale: 0.95 }}
      animate={{ opacity: 1, scale: 1 }}
      transition={{ duration: 0.3 }}
    >
      {/* Main completion card */}
      <Card className="border-green-200 bg-gradient-to-br from-green-50 to-blue-50">
        <CardHeader className="text-center pb-4">
          <motion.div
            initial={{ scale: 0 }}
            animate={{ scale: 1 }}
            transition={{ delay: 0.2, type: 'spring' }}
            className="mx-auto w-20 h-20 bg-green-100 rounded-full flex items-center justify-center mb-4"
          >
            <Award className="w-10 h-10 text-green-600" />
          </motion.div>

          <CardTitle className="text-3xl text-green-800 mb-2">
            Session Complete!
          </CardTitle>

          <div className={cn("inline-flex items-center px-4 py-2 rounded-full text-sm font-medium", performance.color)}>
            <Star className="w-4 h-4 mr-2" />
            {performance.level} Performance
          </div>

          <p className="text-muted-foreground mt-2 max-w-md mx-auto">
            {performance.message}
          </p>
        </CardHeader>

        <CardContent className="space-y-6">
          {/* Key metrics */}
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
            <motion.div
              initial={{ y: 20, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              transition={{ delay: 0.3 }}
              className="text-center"
            >
              <div className="text-3xl font-bold text-green-600">
                {sessionStats.cardsStudied}
              </div>
              <div className="text-sm text-muted-foreground">Cards Studied</div>
            </motion.div>

            <motion.div
              initial={{ y: 20, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              transition={{ delay: 0.4 }}
              className="text-center"
            >
              <div className="text-3xl font-bold text-blue-600">
                {sessionStats.accuracy.toFixed(1)}%
              </div>
              <div className="text-sm text-muted-foreground">Accuracy</div>
            </motion.div>

            <motion.div
              initial={{ y: 20, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              transition={{ delay: 0.5 }}
              className="text-center"
            >
              <div className="text-3xl font-bold text-purple-600">
                {formatTime(sessionStats.duration)}
              </div>
              <div className="text-sm text-muted-foreground">Duration</div>
            </motion.div>

            <motion.div
              initial={{ y: 20, opacity: 0 }}
              animate={{ y: 0, opacity: 1 }}
              transition={{ delay: 0.6 }}
              className="text-center"
            >
              <div className="text-3xl font-bold text-orange-600">
                {overallStats.currentStreak}
              </div>
              <div className="text-sm text-muted-foreground">Day Streak</div>
            </motion.div>
          </div>

          {/* Progress visualization */}
          <div className="space-y-4">
            <div>
              <div className="flex justify-between text-sm mb-2">
                <span>Session Accuracy</span>
                <span>{sessionStats.cardsCorrect}/{sessionStats.cardsStudied}</span>
              </div>
              <Progress value={sessionStats.accuracy} className="h-3" />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
              <div className="flex justify-between">
                <span className="text-muted-foreground">Average per card:</span>
                <span className="font-medium">
                  {Math.round(sessionStats.duration / sessionStats.cardsStudied)}s
                </span>
              </div>
              <div className="flex justify-between">
                <span className="text-muted-foreground">Session type:</span>
                <span className="font-medium capitalize">{sessionType}</span>
              </div>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Achievements */}
      <AnimatePresence>
        {unlockedAchievements.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            transition={{ delay: 0.7 }}
          >
            <Card className="border-yellow-200 bg-gradient-to-br from-yellow-50 to-orange-50">
              <CardHeader>
                <CardTitle className="flex items-center gap-2 text-yellow-800">
                  <Trophy className="w-5 h-5" />
                  Achievements Unlocked!
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                  {unlockedAchievements.map((achievement, index) => (
                    <motion.div
                      key={achievement.id}
                      initial={{ scale: 0, rotate: -10 }}
                      animate={{ scale: 1, rotate: 0 }}
                      transition={{ delay: 0.8 + index * 0.1, type: 'spring' }}
                      className="flex items-center gap-3 p-3 bg-white rounded-lg border border-yellow-200"
                    >
                      <div className="flex-shrink-0">
                        {achievement.icon}
                      </div>
                      <div>
                        <div className="font-semibold text-sm">{achievement.title}</div>
                        <div className="text-xs text-muted-foreground">
                          {achievement.description}
                        </div>
                      </div>
                    </motion.div>
                  ))}
                </div>
              </CardContent>
            </Card>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Progress achievements */}
      {achievements.some(a => !a.unlocked && a.progress !== undefined) && (
        <Card>
          <CardHeader>
            <CardTitle className="flex items-center gap-2">
              <TrendingUp className="w-5 h-5" />
              Goals & Progress
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {achievements
                .filter(a => !a.unlocked && a.progress !== undefined)
                .map((achievement) => (
                  <div key={achievement.id} className="space-y-2">
                    <div className="flex items-center justify-between">
                      <div className="flex items-center gap-2">
                        {achievement.icon}
                        <div>
                          <div className="font-medium text-sm">{achievement.title}</div>
                          <div className="text-xs text-muted-foreground">
                            {achievement.description}
                          </div>
                        </div>
                      </div>
                      <Badge variant="outline">
                        {achievement.progress}/{achievement.maxProgress}
                      </Badge>
                    </div>
                    <Progress 
                      value={(achievement.progress! / achievement.maxProgress!) * 100} 
                      className="h-2" 
                    />
                  </div>
                ))}
            </div>
          </CardContent>
        </Card>
      )}

      {/* Action buttons */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ delay: 1.0 }}
        className="flex gap-3 justify-center"
      >
        <Button
          variant="outline"
          onClick={onRestart}
          className="gap-2"
          size="lg"
        >
          <RotateCcw className="w-4 h-4" />
          Study Again
        </Button>

        <Button
          onClick={onExit}
          className="gap-2"
          size="lg"
        >
          <ArrowRight className="w-4 h-4" />
          Continue Learning
        </Button>
      </motion.div>
    </motion.div>
  )
}

'use client'

import React, { useState, useEffect, useCallback, useRef } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { FlashcardComponent } from './FlashcardComponent'
import { ReviewButtons } from './ReviewButtons'
import { Button } from '@/components/ui/button'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Progress } from '@/components/ui/progress'
import { 
  Word, 
  FlashcardSentence, 
  ReviewResult, 
  StudySession as StudySessionType,
  SessionType 
} from '@/types'
import { QueuedWord } from '@/lib/queue-manager'
import { submitReview, getWordProgress } from '@/lib/reviews'
import { getQueueManager } from '@/lib/queue-manager'
import { aiService } from '@/lib/ai-services'
import { useAuth } from '@/hooks/useAuth'
import { 
  createStudySession, 
  updateStudySession, 
  completeStudySession, 
  pauseStudySession, 
  resumeStudySession,
  abandonStudySession
} from '@/lib/study-sessions'
import { 
  Clock, 
  Target, 
  CheckCircle, 
  XCircle, 
  RotateCcw,
  TrendingUp,
  Award,
  Pause,
  Play,
  StopCircle,
  Timer
} from 'lucide-react'
import { cn } from '@/lib/utils'

const PREFETCH_THRESHOLD = 1 // Start fetching the next chunk when on the second card (1 card left)
const CHUNK_SIZE = 2 // Fetch next 2 cards in the background

interface StudySessionProps {
  words: QueuedWord[]
  sessionType: SessionType
  sessionId?: string
  onSessionComplete: (session: Partial<StudySessionType>) => void
  onExit: () => void
  className?: string
}

interface SessionStats {
  cardsStudied: number
  cardsCorrect: number
  totalReviews: number
  accuracy: number
  startTime: Date
  endTime?: Date
  averageResponseTime: number
}

interface RelearningCard extends QueuedWord {
  originalIndex: number
  timesRelearned: number
  addedToRelearningAt: Date
}

interface CardReview {
  wordId: string
  button: 'again' | 'hard' | 'good' | 'easy'
  responseTime: number
  timestamp: Date
}

export function StudySession({
  words,
  sessionType,
  sessionId: propSessionId,
  onSessionComplete,
  onExit,
  className
}: StudySessionProps) {
  const { user } = useAuth()
  const [currentIndex, setCurrentIndex] = useState(0)
  const [enrichedWords, setEnrichedWords] = useState<QueuedWord[]>(words)
  const [isFetchingNextChunk, setIsFetchingNextChunk] = useState(false)
  const fetchedChunks = useRef(new Set([0])) // Keep track of which chunks are fetched (chunk 0 is initial)

  const [sessionStats, setSessionStats] = useState<SessionStats>({
    cardsStudied: 0,
    cardsCorrect: 0,
    totalReviews: 0,
    accuracy: 0,
    startTime: new Date(),
    averageResponseTime: 0
  })

  // Chunked pre-fetching system manages AI content in background
  const [isSessionComplete, setIsSessionComplete] = useState(false)
  const [responseTimes, setResponseTimes] = useState<number[]>([])
  const [cardReviews, setCardReviews] = useState<CardReview[]>([])
  const [isSubmittingReview, setIsSubmittingReview] = useState(false)
  const [reviewCompleted, setReviewCompleted] = useState(false)
  const [dbSessionId, setDbSessionId] = useState<string | null>(propSessionId || null)
  const [isPaused, setIsPaused] = useState(false)
  const [pauseStartTime, setPauseStartTime] = useState<Date | null>(null)
  const [totalPauseTime, setTotalPauseTime] = useState(0)

  // Re-learning queue for lapsed cards
  const [relearningQueue, setRelearningQueue] = useState<RelearningCard[]>([])
  const [currentlyShowingRelearning, setCurrentlyShowingRelearning] = useState(false)
  const [mainQueueCompleted, setMainQueueCompleted] = useState(false)

  // Get current word from either main queue or re-learning queue
  const currentWord = currentlyShowingRelearning && relearningQueue.length > 0
    ? relearningQueue[0] // Show first word from re-learning queue
    : (enrichedWords && enrichedWords[currentIndex]) // Show word from enriched main queue (with bounds check)

  const totalCards = (enrichedWords?.length || 0) + relearningQueue.length
  const completedCards = currentIndex + (relearningQueue.length - (currentlyShowingRelearning ? relearningQueue.length : 0))
  const progress = totalCards > 0 ? ((completedCards + 1) / totalCards) * 100 : 0

  // Session timer
  const [sessionDuration, setSessionDuration] = useState(0)

  useEffect(() => {
    if (isPaused) return

    const timer = setInterval(() => {
      const now = new Date()
      const elapsed = Math.floor((now.getTime() - sessionStats.startTime.getTime()) / 1000)
      setSessionDuration(elapsed - totalPauseTime)
    }, 1000)

    return () => clearInterval(timer)
  }, [sessionStats.startTime, isPaused, totalPauseTime])

  // Initialize database session
  useEffect(() => {
    if (!dbSessionId) {
      initializeSession()
    }
  }, [])

  const initializeSession = async () => {
    const { data, error } = await createStudySession({
      sessionType
    })

    if (data) {
      setDbSessionId(data.id)
    } else {
      console.error('Failed to create session:', error)
    }
  }

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60)
    const secs = seconds % 60
    return `${mins}:${secs.toString().padStart(2, '0')}`
  }

  // Predictive chunk fetching - loads next chunk in background
  useEffect(() => {
    if (!user || isPaused || currentlyShowingRelearning) return

    const currentChunkIndex = Math.floor(currentIndex / CHUNK_SIZE)
    const nextChunkIndex = currentChunkIndex + 1
    const cardsLeftInChunk = (currentChunkIndex + 1) * CHUNK_SIZE - (currentIndex + 1)

    // Check if we should pre-fetch the next chunk
    if (
      cardsLeftInChunk <= PREFETCH_THRESHOLD &&
      !isFetchingNextChunk &&
      !fetchedChunks.current.has(nextChunkIndex) &&
      (nextChunkIndex * CHUNK_SIZE) < enrichedWords.length
    ) {
      fetchNextChunk(nextChunkIndex)
    }
  }, [currentIndex, enrichedWords, isFetchingNextChunk, user, isPaused, currentlyShowingRelearning])

  const fetchNextChunk = async (chunkIndex: number) => {
    if (!user) return
    setIsFetchingNextChunk(true)
    fetchedChunks.current.add(chunkIndex)

    const startIndex = chunkIndex * CHUNK_SIZE
    const endIndex = Math.min(startIndex + CHUNK_SIZE, enrichedWords.length)
    const chunkToFetch = enrichedWords.slice(startIndex, endIndex)

    console.log(`Pre-fetching content for next 2 cards (${startIndex + 1} to ${endIndex})...`)

    try {
      const contentPromises = chunkToFetch.map(async (word) => {
        // Skip if already has content
        if (word.sentences && word.imageUrl) return null

        const difficulty = word.difficulty <= 2 ? 'beginner' : 
                          word.difficulty <= 4 ? 'intermediate' : 'advanced'

        return aiService.generateFlashcardContent(word.word, difficulty, user.id)
      })

      const contentResults = await Promise.all(contentPromises)

      // Update the enriched words array
      setEnrichedWords(prevWords => {
        const newWords = [...prevWords]
        contentResults.forEach((content, index) => {
          if (!content) return // Skip if content was already there

          const originalIndex = startIndex + index
          const transformedSentences = content.sentences.map((sentence: any) => {
            const sentenceText = typeof sentence === 'string' ? sentence : sentence.sentence || sentence.text || ''
            const blankMarker = '___'

            return {
              sentence: sentenceText,
              blank_position: sentenceText.indexOf(blankMarker) >= 0 ? sentenceText.indexOf(blankMarker) : 0,
              correct_word: newWords[originalIndex].word
            }
          })

          newWords[originalIndex] = {
            ...newWords[originalIndex],
            sentences: transformedSentences,
            imageUrl: content.imageUrl,
            imageDescription: content.imageDescription || null,
          }
        })
        return newWords
      })

      console.log(`Content for next 2 cards (${startIndex + 1} to ${endIndex}) is ready.`)
    } catch (error) {
      console.error(`Failed to pre-fetch chunk ${chunkIndex}:`, error)
      fetchedChunks.current.delete(chunkIndex) // Allow re-fetching on next trigger
    } finally {
      setIsFetchingNextChunk(false)
    }
  }

  // Helper functions for re-learning queue management
  const addToRelearningQueue = useCallback((word: Word | QueuedWord, originalIndex: number) => {
    const relearningCard: RelearningCard = {
      ...word,
      priority: (word as QueuedWord).priority || 'review_soon',
      daysSinceLastReview: (word as QueuedWord).daysSinceLastReview,
      currentEaseFactor: (word as QueuedWord).currentEaseFactor,
      timesReviewed: (word as QueuedWord).timesReviewed,
      lastReview: (word as QueuedWord).lastReview,
      flashcard: (word as QueuedWord).flashcard,
      sentences: (word as QueuedWord).sentences,
      imageUrl: (word as QueuedWord).imageUrl,
      imageDescription: (word as QueuedWord).imageDescription,
      originalIndex,
      timesRelearned: 1,
      addedToRelearningAt: new Date()
    }

    setRelearningQueue(prev => {
      // Check if word is already in re-learning queue
      const existingIndex = prev.findIndex(c => c.id === word.id)
      if (existingIndex >= 0) {
        // Update existing entry - increase times relearned
        const updated = [...prev]
        updated[existingIndex] = {
          ...updated[existingIndex],
          timesRelearned: updated[existingIndex].timesRelearned + 1,
          addedToRelearningAt: new Date()
        }
        return updated
      } else {
        // Add new entry to the end of the queue
        return [...prev, relearningCard]
      }
    })
  }, [])

  const removeFromRelearningQueue = useCallback((wordId: string) => {
    setRelearningQueue(prev => prev.filter(word => word.id !== wordId))
  }, [])

  const shouldShowRelearningCard = useCallback(() => {
    // Show re-learning cards after every 3-4 regular cards, or when main queue is done
    return relearningQueue.length > 0 && (
      mainQueueCompleted || 
      (currentIndex > 0 && currentIndex % 3 === 0)
    )
  }, [relearningQueue.length, mainQueueCompleted, currentIndex])

  const handleReviewButton = useCallback(async (button: 'again' | 'hard' | 'good' | 'easy') => {
    if (!currentWord || isSubmittingReview) return

    setIsSubmittingReview(true)
    const responseTime = Date.now() - sessionStats.startTime.getTime()

    try {
      // Submit review to SM-2 system (no flashcard_id needed for dynamic sentences)
      const { error } = await submitReview({
        wordId: currentWord.id,
        button,
        responseTimeMs: responseTime
      })

      if (error) {
        console.error('Failed to submit review:', error)
      }

      // Update local stats
      const isCorrect = button === 'good' || button === 'easy'

      setSessionStats(prev => {
        const newStats = {
          ...prev,
          cardsStudied: prev.cardsStudied + 1,
          cardsCorrect: prev.cardsCorrect + (isCorrect ? 1 : 0),
          totalReviews: prev.totalReviews + 1,
          accuracy: ((prev.cardsCorrect + (isCorrect ? 1 : 0)) / (prev.cardsStudied + 1)) * 100
        }

        // Update database session
        if (dbSessionId) {
          updateStudySession(dbSessionId, {
            wordsStudied: newStats.cardsStudied,
            wordsCorrect: newStats.cardsCorrect,
            totalReviews: newStats.totalReviews,
            accuracyPercentage: newStats.accuracy
          })
        }

        return newStats
      })

      // Track review for session summary
      const review: CardReview = {
        wordId: currentWord.id,
        button,
        responseTime,
        timestamp: new Date()
      }
      setCardReviews(prev => [...prev, review])
      setResponseTimes(prev => [...prev, responseTime])

      // Handle "Again" button - add to re-learning queue instead of removing completely
      if (button === 'again') {
        if (currentlyShowingRelearning) {
          // If this is already a re-learning word, update its re-learning count
          const relearningWord = relearningQueue[0]
          addToRelearningQueue(relearningWord, relearningWord.originalIndex)
          // Remove current re-learning word (it will be re-added with updated count)
          removeFromRelearningQueue(currentWord.id)
        } else {
          // Add current word to re-learning queue
          addToRelearningQueue(currentWord, currentIndex)
        }
      } else {
        // For other buttons, remove from appropriate queue
        if (currentlyShowingRelearning) {
          removeFromRelearningQueue(currentWord.id)
        } else {
          const queueManager = getQueueManager()
          queueManager.removeFromQueue(currentWord.id)
        }
      }

    } catch (error) {
      console.error('Review submission failed:', error)
    } finally {
      setIsSubmittingReview(false)

      // Immediately trigger next card with minimal delay for smooth animation
      setReviewCompleted(true)
    }
  }, [currentWord, isSubmittingReview, sessionStats.startTime, currentlyShowingRelearning, relearningQueue, currentIndex, addToRelearningQueue, removeFromRelearningQueue])

  const handleReview = useCallback((result: ReviewResult) => {
    // Legacy support for existing ReviewResult interface
    const button = result.quality >= 5 ? 'easy' : 
                  result.quality >= 3 ? 'good' : 
                  result.quality >= 2 ? 'hard' : 'again'
    handleReviewButton(button)
  }, [handleReviewButton])

  const completeSession = useCallback(async () => {
    const endTime = new Date()
    const duration = sessionDuration
    const avgResponseTime = responseTimes.length > 0 
      ? responseTimes.reduce((sum, time) => sum + time, 0) / responseTimes.length 
      : 0

    const finalStats = {
      ...sessionStats,
      endTime,
      averageResponseTime: avgResponseTime
    }

    setSessionStats(finalStats)
    setIsSessionComplete(true)

    // Complete session in database
    if (dbSessionId) {
      await completeStudySession(dbSessionId, {
        wordsStudied: finalStats.cardsStudied,
        wordsCorrect: finalStats.cardsCorrect,
        totalReviews: finalStats.totalReviews,
        sessionDurationSeconds: duration,
        accuracyPercentage: finalStats.accuracy
      })
    }

    // Call completion handler with session data
    onSessionComplete({
      session_type: sessionType,
      words_studied: finalStats.cardsStudied,
      words_correct: finalStats.cardsCorrect,
      total_reviews: finalStats.totalReviews,
      session_duration_seconds: duration,
      accuracy_percentage: finalStats.accuracy,
      started_at: finalStats.startTime.toISOString(),
      ended_at: endTime.toISOString()
    })
  }, [sessionStats, responseTimes, sessionType, onSessionComplete, sessionDuration, dbSessionId])

  const handleNext = useCallback(() => {
    if (currentlyShowingRelearning) {
      // We just finished a re-learning card, go back to main queue
      setCurrentlyShowingRelearning(false)
    } else {
      // We just finished a main queue card
      // Check if we should show a re-learning card next
      if (shouldShowRelearningCard() && !mainQueueCompleted) {
        setCurrentlyShowingRelearning(true)
        return
      }

      // Continue with main queue
      if (currentIndex < (enrichedWords?.length || 0) - 1) {
        setCurrentIndex(prev => prev + 1)
      } else {
        // Main queue completed
        setMainQueueCompleted(true)

        // If there are re-learning words, start showing them
        if (relearningQueue.length > 0) {
          setCurrentlyShowingRelearning(true)
        } else {
          // No re-learning words, session complete
          completeSession()
        }
      }
    }

    // If we're in re-learning mode but no cards left, complete session
    if (mainQueueCompleted && relearningQueue.length === 0) {
      completeSession()
    }
  }, [currentIndex, words?.length, currentlyShowingRelearning, shouldShowRelearningCard, mainQueueCompleted, relearningQueue.length, completeSession])

  // Handle review completion with fast animation-driven transition
  useEffect(() => {
    if (reviewCompleted) {
      const timeoutId = setTimeout(() => {
        handleNext()
        setReviewCompleted(false) // Reset flag
      }, 300) // Reduced from 1000ms to 300ms for responsive experience

      // Cleanup timeout on unmount or if reviewCompleted changes
      return () => clearTimeout(timeoutId)
    }
  }, [reviewCompleted, handleNext])

  const handlePrevious = useCallback(() => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1)
    }
  }, [currentIndex])

  const handlePauseResume = useCallback(async () => {
    if (isPaused) {
      // Resume session
      if (pauseStartTime) {
        const pauseDuration = Math.floor((new Date().getTime() - pauseStartTime.getTime()) / 1000)
        setTotalPauseTime(prev => prev + pauseDuration)
      }
      setIsPaused(false)
      setPauseStartTime(null)

      if (dbSessionId) {
        await resumeStudySession(dbSessionId)
      }
    } else {
      // Pause session
      setIsPaused(true)
      setPauseStartTime(new Date())

      if (dbSessionId) {
        await pauseStudySession(dbSessionId)
      }
    }
  }, [isPaused, pauseStartTime, dbSessionId])

  const handleExitSession = useCallback(async () => {
    if (dbSessionId && !isSessionComplete) {
      await abandonStudySession(dbSessionId)
    }
    onExit()
  }, [dbSessionId, isSessionComplete, onExit])

  const restartSession = useCallback(() => {
    setCurrentIndex(0)
    setSessionStats({
      cardsStudied: 0,
      cardsCorrect: 0,
      totalReviews: 0,
      accuracy: 0,
      startTime: new Date(),
      averageResponseTime: 0
    })
    setResponseTimes([])
    setCardReviews([])
    setIsSessionComplete(false)
    setIsPaused(false)
    setPauseStartTime(null)
    setTotalPauseTime(0)
    setDbSessionId(null)
  }, [])

  // Session completion screen
  if (isSessionComplete) {
    return (
      <motion.div
        className={cn("max-w-2xl mx-auto space-y-6", className)}
        initial={{ opacity: 0, scale: 0.95 }}
        animate={{ opacity: 1, scale: 1 }}
        transition={{ duration: 0.3 }}
      >
        <Card className="border-green-200 bg-green-50/50">
          <CardHeader className="text-center">
            <div className="mx-auto w-16 h-16 bg-green-100 rounded-full flex items-center justify-center mb-4">
              <Award className="w-8 h-8 text-green-600" />
            </div>
            <CardTitle className="text-2xl text-green-800">
              Session Complete!
            </CardTitle>
            <p className="text-green-700">
              Great job on completing your {sessionType} session
            </p>
          </CardHeader>

          <CardContent className="space-y-6">
            {/* Statistics */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
              <div className="text-center">
                <div className="text-2xl font-bold text-foreground">
                  {sessionStats.cardsStudied}
                </div>
                <div className="text-sm text-muted-foreground">Cards Studied</div>
              </div>

              <div className="text-center">
                <div className="text-2xl font-bold text-green-600">
                  {sessionStats.cardsCorrect}
                </div>
                <div className="text-sm text-muted-foreground">Correct</div>
              </div>

              <div className="text-center">
                <div className="text-2xl font-bold text-blue-600">
                  {sessionStats.accuracy.toFixed(1)}%
                </div>
                <div className="text-sm text-muted-foreground">Accuracy</div>
              </div>

              <div className="text-center">
                <div className="text-2xl font-bold text-purple-600">
                  {formatTime(sessionDuration)}
                </div>
                <div className="text-sm text-muted-foreground">Duration</div>
              </div>
            </div>

            {/* Progress visualization */}
            <div className="space-y-2">
              <div className="flex justify-between text-sm">
                <span>Session Progress</span>
                <span>{sessionStats.cardsCorrect}/{sessionStats.cardsStudied}</span>
              </div>
              <Progress value={sessionStats.accuracy} className="h-2" />
            </div>

            {/* Actions */}
            <div className="flex gap-3 justify-center">
              <Button
                variant="outline"
                onClick={restartSession}
                className="gap-2"
              >
                <RotateCcw className="w-4 h-4" />
                Study Again
              </Button>

              <Button
                onClick={handleExitSession}
                className="gap-2"
              >
                <CheckCircle className="w-4 h-4" />
                Return to Dashboard
              </Button>
            </div>
          </CardContent>
        </Card>
      </motion.div>
    )
  }

  // No cards available or no current word
  if (totalCards === 0 || !currentWord) {
    return (
      <div className={cn("max-w-2xl mx-auto", className)}>
        <Card>
          <CardContent className="p-8 text-center">
            <div className="mb-4">
              <Target className="w-12 h-12 mx-auto text-muted-foreground" />
            </div>
            <h3 className="text-xl font-semibold mb-2">No Cards Available</h3>
            <p className="text-muted-foreground mb-4">
              {totalCards === 0 
                ? "There are no words ready for this study session." 
                : "Loading study session..."}
            </p>
            <Button onClick={handleExitSession}>
              Return to Dashboard
            </Button>
          </CardContent>
        </Card>
      </div>
    )
  }

  // Main study interface
  return (
    <div className={cn("max-w-4xl mx-auto h-screen flex flex-col gap-1 sm:gap-2 md:gap-4 py-1 sm:py-2", className)}>
      {/* Session header */}
      <Card className="border-0 shadow-sm bg-muted/30 flex-shrink-0">
        <CardContent className="p-1.5 sm:p-2">
          <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-1 sm:gap-0">
            <div className="flex flex-wrap items-center gap-1.5 sm:gap-2">
              <Badge variant="secondary" className="capitalize text-xs py-0.5 px-1.5">
                {sessionType} Session
              </Badge>

              {currentlyShowingRelearning && (
                <Badge variant="destructive" className="animate-pulse text-xs py-0.5 px-1.5">
                  Re-learning
                </Badge>
              )}

              <div className="flex items-center gap-1 text-xs text-muted-foreground">
                <Clock className="w-3 h-3" />
                {formatTime(sessionDuration)}
              </div>
            </div>

            <div className="flex flex-col sm:flex-row items-start sm:items-center gap-1 sm:gap-2">
                <div className="text-left sm:text-right">
                <div className="text-xs text-muted-foreground leading-tight">Progress</div>
                <div className="text-sm font-semibold leading-tight">
                  {currentIndex + 1} / {enrichedWords?.length || 0}
                </div>
                {relearningQueue.length > 0 && (
                  <div className="text-xs text-orange-600 leading-tight">
                    +{relearningQueue.length} re-learning
                  </div>
                )}
              </div>

              <div className="flex items-center gap-1">
                <Button
                  variant="outline"
                  size="sm"
                  onClick={handlePauseResume}
                  disabled={isSubmittingReview}
                  className="text-xs h-6 px-1.5"
                >
                  {isPaused ? (
                    <>
                      <Play className="w-3 h-3 mr-0.5" />
                      <span className="hidden xs:inline">Resume</span>
                      <span className="xs:hidden">▶</span>
                    </>
                  ) : (
                    <>
                      <Pause className="w-3 h-3 mr-0.5" />
                      <span className="hidden xs:inline">Pause</span>
                      <span className="xs:hidden">⏸</span>
                    </>
                  )}
                </Button>

                <Button
                  variant="outline"
                  size="sm"
                  onClick={handleExitSession}
                  className="text-xs h-6 px-1.5"
                >
                  <StopCircle className="w-3 h-3 mr-0.5" />
                  <span className="hidden xs:inline">Exit</span>
                  <span className="xs:hidden">✕</span>
                </Button>
              </div>
            </div>
          </div>

          {/* Progress bar */}
          <div className="mt-1 sm:mt-1.5">
            <Progress value={progress} className="h-1 sm:h-1.5" />
          </div>
        </CardContent>
      </Card>

      {/* Main flashcard */}
      <AnimatePresence mode="wait">
        {currentWord && (
          <div className="flex-1 space-y-6 min-h-0">
            <FlashcardComponent
              key={currentWord.id}
              word={currentWord}
              sentences={currentWord.sentences || null}
              imageUrl={currentWord.imageUrl || null}
              imageDescription={currentWord.imageDescription || null}
              isGeneratingContent={!currentWord.sentences || !currentWord.imageUrl} // Show loader only if content not ready
              contentGenerationError={null} // Handled by background fetching
              onRegenerateContent={undefined} // Background system handles fetching
              onReview={handleReview}
              onNext={currentIndex < totalCards - 1 ? handleNext : undefined}
              onPrevious={currentIndex > 0 ? handlePrevious : undefined}
              showNavigation={false}
              autoFlip={false}
            />
          </div>
        )}
      </AnimatePresence>

      {/* Session stats sidebar */}
      <Card className="bg-muted/30 border-0 shadow-sm flex-shrink-0">
        <CardContent className="p-2 sm:p-3">
          <div className="grid grid-cols-4 gap-2 sm:gap-3 text-center">
            <div>
              <div className="text-base sm:text-lg font-semibold text-green-600">
                {sessionStats.cardsCorrect}
              </div>
              <div className="text-xs text-muted-foreground">Correct</div>
            </div>

            <div>
              <div className="text-base sm:text-lg font-semibold text-red-600">
                {sessionStats.cardsStudied - sessionStats.cardsCorrect}
              </div>
              <div className="text-xs text-muted-foreground">Incorrect</div>
            </div>

            <div>
              <div className="text-base sm:text-lg font-semibold text-blue-600">
                {sessionStats.accuracy.toFixed(0)}%
              </div>
              <div className="text-xs text-muted-foreground">Accuracy</div>
            </div>

            <div>
              <div className="text-base sm:text-lg font-semibold text-orange-600">
                {relearningQueue.length}
              </div>
              <div className="text-xs text-muted-foreground">Re-learning</div>
            </div>
          </div>
        </CardContent>
      </Card>
    </div>
  )
}

